def next_permutation(xs):
    """
    Mutates xs to the next lexicographic permutation in place; 
    if at last, set to first. Returns None.
    """
    def reverse(i, j):
        while i < j:
            xs[i], xs[j] = xs[j], xs[i]
            i += 1
            j -= 1

    i = len(xs) - 2
    while i >= 0 and xs[i] >= xs[i + 1]:
        i -= 1
    if i < 0:
        reverse(0, len(xs) - 1)
    else:
        j = len(xs) - 1
        while xs[j] <= xs[i]:
            j -= 1
        xs[i], xs[j] = xs[j], xs[i]
        reverse(i + 1, len(xs) - 1)
    return None
